def cal_priority(available_time, num_neighboring_operation, utilization, processing_tm, delivery_time=None):
    if delivery_time is None:
        delivery_time = float('inf')
    epsilon = 1e-10
    denominator = num_neighboring_operation + 1
    if denominator == 0:
        denominator = epsilon
    congestion = (available_time + processing_tm) / denominator
    efficiency = 1.0 / (utilization + epsilon)
    if delivery_time == float('inf'):
        priority = float('inf')
    else:
        # Combine due-date urgency (exponential of delivery_time), congestion, and efficiency penalty
        priority = (delivery_time ** 0.5) * (congestion ** 0.3) - efficiency * 0.3 + (utilization * 0.2)
    return priority

